SELECT user_id, note_text
FROM sermon_notes
WHERE note_type = 'question';

SELECT title 
FROM sermons 
WHERE sermon_id = 0;

SELECT AVG(rating_score) AS average_rating
FROM sermon_ratings
WHERE sermon_id = 0;

SELECT COUNT(sermon_id) AS total_sermons
FROM sermons
WHERE speaker_id = 0;

SELECT title, date 
FROM sermons 
ORDER BY date DESC;
